{
  "name": "IEADMS Kids - Sistema de Controle",
  "description": "Sistema completo para controle de fluxo de crianças no Culto Kids da Igreja IEADMS, com check-in por código, gestão de histórico e área dos pais.",
  "requestFramePermissions": [
    "camera"
  ]
}

export type CultoType = 'Santa Ceia' | 'Reunião de Obreiros' | 'Umademats' | 'CIFAD' | 'Outros';

export interface Crianca {
  id: string;
  nome: string;
  sobrenome: string;
  dataNascimento: string;
  responsavelNome: string;
  whatsapp: string;
  observacoes?: string;
  createdAt: string;
}

export interface CheckIn {
  id: string;
  idCrianca: string;
  idCulto: string;
  horaEntrada: string;
  horaSaida?: string;
  quemRetirou?: string;
  status: 'presente' | 'saiu';
}

export interface PreCheckIn {
  id: string;
  idCrianca: string;
  idCulto: string;
  codigo: string; // KIDS-####
  status: 'pendente' | 'confirmado';
  dataHoraPreCheckin: string;
  dataHoraCheckin?: string;
}

export interface Culto {
  id: string;
  tipo: CultoType;
  tipoManual?: string;
  data: string;
  horaInicio: string;
  horaFim?: string;
  responsaveis: string;
  status: 'ativo' | 'encerrado';
}

export interface AuthState {
  isAuthenticated: boolean;
  email: string | null;
}

import { Crianca, Culto, CheckIn, PreCheckIn } from '../types';

const STORAGE_KEYS = {
  CRIANCAS: 'ieadms_kids_criancas',
  CULTOS: 'ieadms_kids_cultos',
  CHECKINS: 'ieadms_kids_checkins',
  PRE_CHECKINS: 'ieadms_kids_precheckins'
};

// Initial data for demo
const initialCriancas: Crianca[] = [
  {
    id: '1',
    nome: 'Miguel',
    sobrenome: 'Santos',
    dataNascimento: '2018-05-15',
    responsavelNome: 'João Santos',
    whatsapp: '5567999999999',
    createdAt: new Date().toISOString()
  },
  {
    id: '2',
    nome: 'Alice',
    sobrenome: 'Oliveira',
    dataNascimento: '2019-10-22',
    responsavelNome: 'Maria Oliveira',
    whatsapp: '5567988888888',
    createdAt: new Date().toISOString()
  }
];

export const storageService = {
  getData: <T,>(key: string): T[] => {
    const data = localStorage.getItem(key);
    return data ? JSON.parse(data) : [];
  },

  saveData: <T,>(key: string, data: T[]): void => {
    localStorage.setItem(key, JSON.stringify(data));
  },

  initialize: () => {
    if (!localStorage.getItem(STORAGE_KEYS.CRIANCAS)) {
      storageService.saveData(STORAGE_KEYS.CRIANCAS, initialCriancas);
    }
  },

  // Criancas
  getCriancas: () => storageService.getData<Crianca>(STORAGE_KEYS.CRIANCAS),
  addCrianca: (crianca: Crianca) => {
    const list = storageService.getCriancas();
    storageService.saveData(STORAGE_KEYS.CRIANCAS, [...list, crianca]);
  },

  // Cultos
  getCultos: () => storageService.getData<Culto>(STORAGE_KEYS.CULTOS),
  getActiveCulto: () => storageService.getCultos().find(c => c.status === 'ativo'),
  addCulto: (culto: Culto) => {
    const list = storageService.getCultos();
    storageService.saveData(STORAGE_KEYS.CULTOS, [...list, culto]);
  },
  updateCulto: (updatedCulto: Culto) => {
    const list = storageService.getCultos().map(c => c.id === updatedCulto.id ? updatedCulto : c);
    storageService.saveData(STORAGE_KEYS.CULTOS, list);
  },

  // Checkins
  getCheckins: () => storageService.getData<CheckIn>(STORAGE_KEYS.CHECKINS),
  addCheckin: (checkin: CheckIn) => {
    const list = storageService.getCheckins();
    storageService.saveData(STORAGE_KEYS.CHECKINS, [...list, checkin]);
  },
  updateCheckin: (updated: CheckIn) => {
    const list = storageService.getCheckins().map(c => c.id === updated.id ? updated : c);
    storageService.saveData(STORAGE_KEYS.CHECKINS, list);
  },

  // PreCheckins
  getPreCheckins: () => storageService.getData<PreCheckIn>(STORAGE_KEYS.PRE_CHECKINS),
  addPreCheckin: (pre: PreCheckIn) => {
    const list = storageService.getPreCheckins();
    storageService.saveData(STORAGE_KEYS.PRE_CHECKINS, [...list, pre]);
  },
  updatePreCheckin: (updated: PreCheckIn) => {
    const list = storageService.getPreCheckins().map(c => c.id === updated.id ? updated : c);
    storageService.saveData(STORAGE_KEYS.PRE_CHECKINS, list);
  },
  getPreCheckinByCode: (code: string) => {
    return storageService.getPreCheckins().find(p => p.codigo === code && p.status === 'pendente');
  }
};

import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { ICONS, COLORS } from '../constants';
import { storageService } from '../services/storageService';

interface LayoutProps {
  children: React.ReactNode;
  isAuthenticated: boolean;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, isAuthenticated, onLogout }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const activeCulto = storageService.getActiveCulto();

  const menuItems = [
    { label: 'Painel', path: '/', icon: ICONS.BarChart },
    { label: 'Cultos', path: '/cultos', icon: ICONS.Calendar },
    { label: 'Crianças', path: '/criancas', icon: ICONS.Baby },
    { label: 'Estatísticas', path: '/estatisticas', icon: ICONS.BarChart },
  ];

  if (!isAuthenticated && !location.pathname.startsWith('/pais') && location.pathname !== '/login') {
    return <>{children}</>;
  }

  // Simplified layout for Parents area
  if (location.pathname.startsWith('/pais')) {
    return (
      <div className="min-h-screen bg-gray-light flex flex-col">
        <header className="bg-purple-main text-white p-4 shadow-lg flex items-center justify-between">
          <Link to="/pais" className="flex items-center gap-2">
            <div className="bg-white p-2 rounded-full">
              <img src="https://picsum.photos/40/40" alt="Logo" className="w-8 h-8 rounded-full" />
            </div>
            <span className="kids-font text-xl font-bold">IEADMS Kids</span>
          </Link>
          <div className="text-xs text-yellow-main font-bold">ÁREA DOS PAIS</div>
        </header>
        <main className="flex-1 p-4 md:p-8 max-w-4xl mx-auto w-full">
          {children}
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-light flex flex-col md:flex-row">
      {/* Sidebar for Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-purple-dark text-white fixed h-full shadow-2xl z-20">
        <div className="p-6 border-b border-purple-main/30">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2 rounded-xl">
              <img src="https://picsum.photos/50/50" alt="Logo" className="w-10 h-10 rounded-lg" />
            </div>
            <div>
              <h1 className="kids-font text-xl font-bold leading-tight">IEADMS</h1>
              <span className="text-yellow-main text-sm font-bold tracking-widest">KIDS</span>
            </div>
          </div>
        </div>

        <nav className="flex-1 py-6">
          {menuItems.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center gap-4 px-6 py-4 transition-all duration-200 border-l-4 ${
                  isActive 
                    ? 'bg-purple-main text-white border-yellow-main' 
                    : 'text-purple-light border-transparent hover:bg-purple-main/20 hover:text-white'
                }`}
              >
                {item.icon}
                <span className="font-medium">{item.label}</span>
              </Link>
            );
          })}
        </nav>

        {activeCulto && (
          <div className="p-4 mx-4 mb-4 bg-green-600/20 border border-green-500/50 rounded-xl">
            <div className="flex items-center gap-2 text-green-400 mb-1">
              <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
              <span className="text-xs font-bold uppercase">Ativo Agora</span>
            </div>
            <p className="text-sm font-bold">{activeCulto.tipo}</p>
            <button 
              onClick={() => navigate(`/cultos/ativo/${activeCulto.id}`)}
              className="mt-2 text-xs bg-green-600 hover:bg-green-500 text-white w-full py-2 rounded-lg font-bold transition-colors"
            >
              GERENCIAR
            </button>
          </div>
        )}

        <button 
          onClick={onLogout}
          className="m-6 p-4 flex items-center gap-3 text-red-400 hover:text-red-300 transition-colors border border-red-400/20 rounded-xl"
        >
          {ICONS.LogOut}
          <span className="font-bold">Sair do Sistema</span>
        </button>
      </aside>

      {/* Mobile Top Header */}
      <header className="md:hidden bg-purple-dark text-white p-4 flex items-center justify-between sticky top-0 z-30 shadow-md">
        <div className="flex items-center gap-2">
          <div className="bg-white p-1 rounded-lg">
            <img src="https://picsum.photos/30/30" alt="Logo" className="w-6 h-6 rounded" />
          </div>
          <span className="kids-font font-bold">IEADMS KIDS</span>
        </div>
        <button onClick={onLogout} className="text-red-400">{ICONS.LogOut}</button>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 md:ml-64 p-4 md:p-8">
        <div className="max-w-6xl mx-auto">
          {children}
        </div>
      </main>

      {/* Mobile Bottom Navigation */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 flex justify-around py-2 px-4 z-30">
        {menuItems.map((item) => {
          const isActive = location.pathname === item.path;
          return (
            <Link
              key={item.path}
              to={item.path}
              className={`flex flex-col items-center gap-1 p-2 ${
                isActive ? 'text-purple-main' : 'text-gray-text'
              }`}
            >
              {item.icon}
              <span className="text-[10px] font-bold uppercase">{item.label}</span>
            </Link>
          );
        })}
      </nav>
    </div>
  );
};

export default Layout;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ADMIN_CREDENTIALS, ICONS } from '../constants';

interface LoginProps {
  onLogin: (success: boolean) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (email === ADMIN_CREDENTIALS.email && password === ADMIN_CREDENTIALS.password) {
      onLogin(true);
      navigate('/');
    } else {
      setError('Credenciais inválidas. Tente novamente.');
    }
  };

  return (
    <div className="min-h-screen bg-purple-dark flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden p-8 md:p-12">
        <div className="text-center mb-10">
          <div className="bg-purple-main inline-block p-4 rounded-3xl shadow-inner mb-6">
            <img src="https://picsum.photos/100/100" alt="Logo" className="w-16 h-16 md:w-20 md:h-20" />
          </div>
          <h1 className="kids-font text-3xl font-bold text-purple-dark">IEADMS Kids</h1>
          <p className="text-gray-text mt-2 font-medium">Controle de Fluxo Administrativo</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          <div>
            <label className="block text-sm font-bold text-gray-text uppercase tracking-wider mb-2">E-mail</label>
            <div className="relative">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-purple-main">
                {ICONS.Users}
              </span>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none px-12 py-4 rounded-2xl transition-all"
                placeholder="nome@igreja.com.br"
                required
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-text uppercase tracking-wider mb-2">Senha</label>
            <div className="relative">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-purple-main">
                {ICONS.Key}
              </span>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none px-12 py-4 rounded-2xl transition-all"
                placeholder="••••••••"
                required
              />
            </div>
          </div>

          {error && (
            <div className="bg-red-50 text-red-500 p-4 rounded-xl text-sm font-bold text-center">
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-purple-main hover:bg-purple-dark text-white font-bold py-5 rounded-2xl shadow-lg transition-all transform hover:-translate-y-1 active:scale-95"
          >
            ENTRAR NO SISTEMA
          </button>
        </form>

        <div className="mt-10 text-center">
          <button 
            onClick={() => navigate('/pais')}
            className="text-purple-main font-bold hover:underline"
          >
            Sou responsável e quero cadastrar meu filho
          </button>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { CULTO_TYPES, ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { CultoType } from '../types';

const CultoIniciar: React.FC = () => {
  const navigate = useNavigate();
  const [tipo, setTipo] = useState<CultoType>('Santa Ceia');
  const [tipoManual, setTipoManual] = useState('');
  const [data, setData] = useState(new Date().toISOString().split('T')[0]);
  const [responsaveis, setResponsaveis] = useState('');

  const handleStart = (e: React.FormEvent) => {
    e.preventDefault();

    // Check if there's already an active culto
    const active = storageService.getActiveCulto();
    if (active) {
      alert('Já existe um culto em andamento. Encerre-o antes de iniciar um novo.');
      navigate(`/cultos/ativo/${active.id}`);
      return;
    }

    const newCulto = {
      id: Date.now().toString(),
      tipo,
      tipoManual: tipo === 'Outros' ? tipoManual : undefined,
      data,
      horaInicio: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      responsaveis,
      status: 'ativo' as const
    };

    storageService.addCulto(newCulto);
    navigate(`/cultos/ativo/${newCulto.id}`);
  };

  return (
    <div className="max-w-2xl mx-auto animate-in slide-in-from-bottom duration-500">
      <button 
        onClick={() => navigate(-1)}
        className="mb-6 flex items-center gap-2 text-purple-main font-bold"
      >
        {ICONS.ArrowLeft} Voltar
      </button>

      <div className="bg-white rounded-3xl shadow-xl p-8 md:p-12 border-b-8 border-yellow-main">
        <h1 className="text-3xl font-black text-purple-dark mb-2">Iniciar Novo Culto</h1>
        <p className="text-gray-text mb-10 font-medium">Preencha as informações básicas para começar o controle de entrada.</p>

        <form onSubmit={handleStart} className="space-y-8">
          <div>
            <label className="block text-sm font-bold text-gray-text uppercase tracking-wider mb-3">Tipo de Culto</label>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
              {CULTO_TYPES.map(t => (
                <button
                  key={t}
                  type="button"
                  onClick={() => setTipo(t as CultoType)}
                  className={`p-4 rounded-2xl border-2 font-bold transition-all ${
                    tipo === t 
                      ? 'bg-purple-main border-purple-main text-white shadow-lg' 
                      : 'bg-white border-gray-200 text-gray-600 hover:border-purple-main/30'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          {tipo === 'Outros' && (
            <div className="animate-in fade-in slide-in-from-top-2 duration-300">
              <label className="block text-sm font-bold text-gray-text uppercase tracking-wider mb-2">Nome do Evento</label>
              <input
                type="text"
                value={tipoManual}
                onChange={(e) => setTipoManual(e.target.value)}
                className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none p-4 rounded-2xl transition-all"
                placeholder="Ex: Congressinho Kids 2024"
                required
              />
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-bold text-gray-text uppercase tracking-wider mb-2">Data</label>
              <input
                type="date"
                min={new Date().toISOString().split('T')[0]}
                value={data}
                onChange={(e) => setData(e.target.value)}
                className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none p-4 rounded-2xl transition-all font-bold"
                required
              />
            </div>
            <div>
              <label className="block text-sm font-bold text-gray-text uppercase tracking-wider mb-2">Hora (Auto)</label>
              <input
                type="text"
                disabled
                value={new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                className="w-full bg-gray-100 border-2 border-transparent p-4 rounded-2xl font-bold text-gray-400"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-text uppercase tracking-wider mb-2">Responsáveis de Hoje</label>
            <textarea
              value={responsaveis}
              onChange={(e) => setResponsaveis(e.target.value)}
              className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none p-4 rounded-2xl transition-all"
              placeholder="Ex: Tio João, Tia Maria, Voluntária Ana"
              rows={3}
              required
            />
          </div>

          <button
            type="submit"
            className="w-full bg-purple-main hover:bg-purple-dark text-white font-black py-6 rounded-2xl shadow-xl flex items-center justify-center gap-3 transition-all transform hover:scale-105"
          >
            {ICONS.Play}
            ABRIR PORTAS DO KIDS
          </button>
        </form>
      </div>
    </div>
  );
};

export default CultoIniciar;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ICONS, COLORS } from '../constants';
import { storageService } from '../services/storageService';
import { Crianca, CheckIn } from '../types';

const CultoAtivo: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [culto, setCulto] = useState(storageService.getCultos().find(c => c.id === id));
  const [checkins, setCheckins] = useState(storageService.getCheckins().filter(c => c.idCulto === id));
  const [criancas, setCriancas] = useState(storageService.getCriancas());

  const [searchTerm, setSearchTerm] = useState('');
  const [codeEntry, setCodeEntry] = useState('');
  const [showCheckoutModal, setShowCheckoutModal] = useState<CheckIn | null>(null);
  const [checkoutResponsible, setCheckoutResponsible] = useState('');

  // Auto-refresh data
  useEffect(() => {
    if (!culto || culto.status === 'encerrado') {
      navigate('/cultos');
    }
  }, [culto, navigate]);

  const activeCheckins = checkins.filter(c => c.status === 'presente');
  const pastCheckins = checkins.filter(c => c.status === 'saiu');

  const handleManualCheckIn = (crianca: Crianca) => {
    // Check if already in
    if (activeCheckins.some(c => c.idCrianca === crianca.id)) {
      alert(`${crianca.nome} já está no culto.`);
      return;
    }

    const newCheckin: CheckIn = {
      id: Date.now().toString(),
      idCrianca: crianca.id,
      idCulto: id!,
      horaEntrada: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      status: 'presente'
    };

    storageService.addCheckin(newCheckin);
    setCheckins(prev => [...prev, newCheckin]);
    setSearchTerm('');
    alert(`Check-in de ${crianca.nome} realizado!`);
  };

  const handleCodeCheckIn = () => {
    const preCheckin = storageService.getPreCheckinByCode(codeEntry.toUpperCase());
    if (!preCheckin) {
      alert('Código inválido ou já utilizado.');
      return;
    }

    if (preCheckin.idCulto !== id) {
       // Allow use in current active culto if it was generic
    }

    const crianca = criancas.find(c => c.id === preCheckin.idCrianca);
    if (!crianca) return;

    const newCheckin: CheckIn = {
      id: Date.now().toString(),
      idCrianca: crianca.id,
      idCulto: id!,
      horaEntrada: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      status: 'presente'
    };

    storageService.addCheckin(newCheckin);
    storageService.updatePreCheckin({
      ...preCheckin,
      status: 'confirmado',
      dataHoraCheckin: new Date().toISOString()
    });

    setCheckins(prev => [...prev, newCheckin]);
    setCodeEntry('');
    alert(`Check-in via código confirmado para ${crianca.nome}!`);
  };

  const handleCheckout = () => {
    if (!showCheckoutModal) return;
    if (!checkoutResponsible) {
      alert('Informe quem está retirando a criança.');
      return;
    }

    const updated = {
      ...showCheckoutModal,
      status: 'saiu' as const,
      horaSaida: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      quemRetirou: checkoutResponsible
    };

    storageService.updateCheckin(updated);
    setCheckins(prev => prev.map(c => c.id === updated.id ? updated : c));
    setShowCheckoutModal(null);
    setCheckoutResponsible('');
  };

  const handleEndCulto = () => {
    if (activeCheckins.length > 0) {
      alert('Ainda há crianças presentes no KIDS. Realize o checkout de todos antes de encerrar.');
      return;
    }

    if (confirm('Tem certeza que deseja encerrar o culto?')) {
      const updatedCulto = {
        ...culto!,
        status: 'encerrado' as const,
        horaFim: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
      };
      storageService.updateCulto(updatedCulto);
      navigate('/cultos');
    }
  };

  const filteredSearch = searchTerm.length >= 2 
    ? criancas.filter(c => (c.nome + ' ' + c.sobrenome).toLowerCase().includes(searchTerm.toLowerCase()))
    : [];

  return (
    <div className="space-y-6">
      {/* Fixed Operational Header */}
      <div className="sticky top-0 z-10 md:static bg-white p-4 md:p-6 rounded-3xl shadow-lg border-l-8 border-green-500 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
