import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { PreCheckIn } from '../types';

const PreCheckin: React.FC = () => {
  const navigate = useNavigate();
  const activeCulto = storageService.getActiveCulto();
  const criancas = storageService.getCriancas();

  const [step, setStep] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedKid, setSelectedKid] = useState<string | null>(null);
  const [generatedCode, setGeneratedCode] = useState('');

  const filtered = searchTerm.length >= 2 
    ? criancas.filter(c => (c.nome + ' ' + c.sobrenome).toLowerCase().includes(searchTerm.toLowerCase()))
    : [];

  const handleGenerateCode = (kidId: string) => {
    if (!activeCulto) return;

    // Check if there is already a pending precheckin for this kid in this culto
    const existing = storageService.getPreCheckins().find(p => p.idCrianca === kidId && p.idCulto === activeCulto.id && p.status === 'pendente');

    if (existing) {
      setGeneratedCode(existing.codigo);
      setStep(3);
      return;
    }

    const code = `KIDS-${Math.floor(1000 + Math.random() * 9000)}`;
    const newPre: PreCheckIn = {
      id: Date.now().toString(),
      idCrianca: kidId,
      idCulto: activeCulto.id,
      codigo: code,
      status: 'pendente',
      dataHoraPreCheckin: new Date().toISOString()
    };

    storageService.addPreCheckin(newPre);
    setGeneratedCode(code);
    setStep(3);
  };

  if (!activeCulto) {
    return (
      <div className="text-center py-20 bg-white rounded-3xl p-10 shadow-xl">
        <div className="bg-red-100 text-red-500 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 text-3xl">⚠️</div>
        <h2 className="text-2xl font-black text-purple-dark mb-4 uppercase">Ops! Portões Fechados</h2>
        <p className="text-gray-text mb-8">Não há nenhum culto ativo no momento. Por favor, tente novamente durante o horário de culto.</p>
        <button onClick={() => navigate('/pais')} className="bg-purple-main text-white px-8 py-4 rounded-2xl font-bold">VOLTAR AO INÍCIO</button>
      </div>
    );
  }

  return (
    <div className="max-w-xl mx-auto">
      {step === 1 && (
        <div className="animate-in fade-in slide-in-from-right duration-400">
          <button onClick={() => navigate('/pais')} className="mb-6 flex items-center gap-2 text-purple-main font-bold">
            {ICONS.ArrowLeft} Voltar
          </button>
          <div className="bg-white p-8 md:p-10 rounded-[2.5rem] shadow-xl border-b-8 border-purple-main">
            <h2 className="text-3xl font-black text-purple-dark mb-2 uppercase">Quem vai ao Culto?</h2>
            <p className="text-gray-text mb-8">Digite o nome do seu filho para localizá-lo em nosso sistema.</p>

            <div className="relative mb-6">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">{ICONS.Search}</span>
              <input 
                type="text"
                placeholder="Nome da criança..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-12 pr-4 py-5 rounded-3xl bg-gray-light border-2 border-transparent focus:border-purple-main outline-none font-bold"
              />
            </div>

            <div className="space-y-3 max-h-80 overflow-y-auto">
              {filtered.map(c => (
                <button 
                  key={c.id}
                  onClick={() => handleGenerateCode(c.id)}
                  className="w-full flex items-center justify-between p-5 bg-purple-50 hover:bg-purple-100 rounded-2xl border-2 border-purple-100 transition-all text-left group"
                >
                  <div>
                    <p className="font-black text-purple-dark text-lg">{c.nome} {c.sobrenome}</p>
                    <p className="text-xs font-bold text-gray-400 uppercase">Resp: {c.responsavelNome}</p>
                  </div>
                  <div className="bg-white p-2 rounded-xl text-purple-main group-hover:scale-110 transition-transform shadow-sm">
                    {ICONS.ChevronRight}
                  </div>
                </button>
              ))}
              {searchTerm.length >= 2 && filtered.length === 0 && (
                <div className="text-center py-10 bg-gray-50 rounded-3xl">
                  <p className="text-gray-text mb-4 font-bold italic">Não encontramos esse cadastro.</p>
                  <button 
                    onClick={() => navigate('/pais/cadastro')}
                    className="bg-yellow-main text-purple-dark px-6 py-3 rounded-2xl font-black shadow-md"
                  >
                    CADASTRAR MEU FILHO
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="animate-in zoom-in duration-500 text-center">
          <div className="bg-white p-10 md:p-16 rounded-[3rem] shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-4 bg-green-500"></div>

            <div className="bg-green-100 text-green-600 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8 text-4xl shadow-inner">
              {ICONS.CheckCircle}
            </div>

            <h2 className="text-3xl font-black text-purple-dark mb-4 uppercase">PRÉ-CHECK-IN REALIZADO!</h2>
            <p className="text-gray-text mb-10 font-medium">Apresente o código abaixo para o voluntário na recepção do Kids:</p>

            <div className="bg-purple-dark text-yellow-main p-8 rounded-3xl mb-10 shadow-inner">
              <span className="text-sm font-black uppercase opacity-60 block mb-2 tracking-widest">Seu Código é</span>
              <span className="text-5xl md:text-6xl font-black tracking-widest block">{generatedCode}</span>
            </div>

            <button 
              onClick={() => navigate('/pais')}
              className="w-full py-5 bg-gray-100 text-purple-dark font-black rounded-3xl hover:bg-gray-200 transition-colors"
