import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { CULTO_TYPES, ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { CultoType } from '../types';

const CultoIniciar: React.FC = () => {
  const navigate = useNavigate();
  const [tipo, setTipo] = useState<CultoType>('Santa Ceia');
  const [tipoManual, setTipoManual] = useState('');
  const [responsaveis, setResponsaveis] = useState('');
  const [data, setData] = useState(new Date().toISOString().split('T')[0]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const active = await storageService.getActiveCulto();
    if (active) {
      alert('Já existe um culto ativo. Encerre-o antes de iniciar outro.');
      setIsSubmitting(false);
      return;
    }

    const newCulto = {
      tipo,
      tipoManual: tipo === 'Outros' ? tipoManual : undefined,
      data,
      horaInicio: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      responsaveis,
      status: 'ativo' as const
    };

    try {
      const docRef = await storageService.addCulto(newCulto);
      navigate(`/cultos/ativo/${docRef.id}`);
    } catch (error) {
      alert('Erro ao iniciar culto. Tente novamente.');
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto animate-in zoom-in-95 duration-500">
      <button 
        onClick={() => navigate(-1)}
        className="mb-10 flex items-center gap-2 text-purple-main font-black uppercase tracking-widest text-xs hover:gap-3 transition-all"
      >
        {ICONS.ArrowLeft} Voltar
      </button>

      <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border-b-[12px] border-yellow-main">
        <div className="bg-purple-main p-10 md:p-14 text-white">
          <h1 className="text-4xl font-black mb-4 tracking-tighter uppercase text-white">Iniciar Novo Culto</h1>
          <p className="text-white/70 font-medium text-lg">Defina os detalhes da sessão de hoje para abrir o check-in.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-10 md:p-14 space-y-10">
          <section>
            <label className="block text-xs font-black text-gray-text uppercase tracking-widest mb-6">Tipo de Celebração</label>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
              {CULTO_TYPES.map(t => (
                <button
                  key={t}
                  type="button"
                  onClick={() => setTipo(t as CultoType)}
                  className={`p-5 rounded-3xl border-2 font-black transition-all text-sm uppercase tracking-wide ${
                    tipo === t 
                      ? 'bg-purple-main border-purple-main text-white shadow-xl scale-105' 
                      : 'bg-white border-gray-100 text-gray-500 hover:border-purple-main/20'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </section>

          {tipo === 'Outros' && (
            <div className="animate-in fade-in slide-in-from-top-4 duration-300">
              <label className="block text-xs font-black text-gray-text uppercase tracking-widest mb-3">Qual o nome deste culto?</label>
              <input
                type="text"
                required
                value={tipoManual}
                onChange={(e) => setTipoManual(e.target.value)}
                className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none p-6 rounded-[1.5rem] font-bold text-lg"
                placeholder="Ex: Congresso Kids Regional"
              />
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
              <label className="block text-xs font-black text-gray-text uppercase tracking-widest mb-3">Data do Evento</label>
              <input
                type="date"
                required
                value={data}
                onChange={(e) => setData(e.target.value)}
                className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none p-6 rounded-[1.5rem] font-bold text-lg"
              />
            </div>
            <div>
              <label className="block text-xs font-black text-gray-text uppercase tracking-widest mb-3">Hora de Início (Auto)</label>
              <div className="w-full bg-gray-100 p-6 rounded-[1.5rem] font-black text-lg text-gray-400 flex items-center gap-3">
                {ICONS.Clock} {new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>

          <div>
            <label className="block text-xs font-black text-gray-text uppercase tracking-widest mb-3">Equipe Responsável</label>
            <textarea
              required
              rows={3}
              value={responsaveis}
              onChange={(e) => setResponsaveis(e.target.value)}
              className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none p-6 rounded-[1.5rem] font-bold text-lg resize-none"
              placeholder="Ex: Tio João, Tia Maria, Voluntária Sarah..."
            />
          </div>

          <button
            type="submit"
            disabled={isSubmitting}
            className="w-full bg-yellow-main hover:bg-yellow-secondary text-purple-dark font-black py-8 rounded-[2rem] shadow-2xl transition-all transform hover:-translate-y-1 active:scale-95 text-xl tracking-tight uppercase disabled:opacity-50"
          >
            {isSubmitting ? 'INICIANDO...' : 'ABRIR CHECK-IN AGORA'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default CultoIniciar;

import { initializeApp } from 'firebase/app';
import { 
  getFirestore, 
  collection, 
  addDoc, 
  getDocs, 
  updateDoc, 
  doc, 
  query, 
  where, 
  onSnapshot,
  Timestamp,
  orderBy,
  limit
} from 'firebase/firestore';
import { firebaseConfig } from './firebaseConfig';
import { Crianca, Culto, CheckIn, PreCheckIn } from '../types';

const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

const COLLECTIONS = {
  CRIANCAS: 'criancas',
  CULTOS: 'cultos',
  CHECKINS: 'checkins',
  PRECHECKINS: 'pre_checkins'
};

export const storageService = {
  // Criancas
  getCriancas: async () => {
    const snapshot = await getDocs(collection(db, COLLECTIONS.CRIANCAS));
    return snapshot.docs.map(d => ({ id: d.id, ...d.data() } as Crianca));
  },
  addCrianca: async (c: Omit<Crianca, 'id'>) => {
    return await addDoc(collection(db, COLLECTIONS.CRIANCAS), c);
  },

  // Cultos
  getCultos: async () => {
    const q = query(collection(db, COLLECTIONS.CULTOS), orderBy('data', 'desc'));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(d => ({ id: d.id, ...d.data() } as Culto));
  },
  getActiveCulto: async () => {
    const q = query(collection(db, COLLECTIONS.CULTOS), where('status', '==', 'ativo'), limit(1));
    const snapshot = await getDocs(q);
    if (snapshot.empty) return null;
    return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as Culto;
  },
  subscribeToActiveCulto: (callback: (culto: Culto | null) => void) => {
    const q = query(collection(db, COLLECTIONS.CULTOS), where('status', '==', 'ativo'), limit(1));
    return onSnapshot(q, (snapshot) => {
      if (snapshot.empty) callback(null);
      else callback({ id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as Culto);
    });
  },
  addCulto: async (c: Omit<Culto, 'id'>) => {
    return await addDoc(collection(db, COLLECTIONS.CULTOS), c);
  },
  updateCulto: async (id: string, updated: Partial<Culto>) => {
    const ref = doc(db, COLLECTIONS.CULTOS, id);
    return await updateDoc(ref, updated);
  },

  // Checkins
  getCheckins: async (idCulto: string) => {
    const q = query(collection(db, COLLECTIONS.CHECKINS), where('idCulto', '==', idCulto));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(d => ({ id: d.id, ...d.data() } as CheckIn));
  },
  getAllCheckins: async () => {
    const snapshot = await getDocs(collection(db, COLLECTIONS.CHECKINS));
    return snapshot.docs.map(d => ({ id: d.id, ...d.data() } as CheckIn));
  },
  subscribeToCheckins: (idCulto: string, callback: (checkins: CheckIn[]) => void) => {
    const q = query(collection(db, COLLECTIONS.CHECKINS), where('idCulto', '==', idCulto));
    return onSnapshot(q, (snapshot) => {
      callback(snapshot.docs.map(d => ({ id: d.id, ...d.data() } as CheckIn)));
    });
  },
  addCheckin: async (c: Omit<CheckIn, 'id'>) => {
    return await addDoc(collection(db, COLLECTIONS.CHECKINS), c);
  },
  updateCheckin: async (id: string, updated: Partial<CheckIn>) => {
    const ref = doc(db, COLLECTIONS.CHECKINS, id);
    return await updateDoc(ref, updated);
  },

  // PreCheckins
  getPreCheckins: async () => {
    const snapshot = await getDocs(collection(db, COLLECTIONS.PRECHECKINS));
    return snapshot.docs.map(d => ({ id: d.id, ...d.data() } as PreCheckIn));
  },
  subscribeToPreCheckins: (callback: (pre: PreCheckIn[]) => void) => {
    return onSnapshot(collection(db, COLLECTIONS.PRECHECKINS), (snapshot) => {
      callback(snapshot.docs.map(d => ({ id: d.id, ...d.data() } as PreCheckIn)));
    });
  },
  addPreCheckin: async (p: Omit<PreCheckIn, 'id'>) => {
    return await addDoc(collection(db, COLLECTIONS.PRECHECKINS), p);
  },
  updatePreCheckin: async (id: string, updated: Partial<PreCheckIn>) => {
    const ref = doc(db, COLLECTIONS.PRECHECKINS, id);
    return await updateDoc(ref, updated);
  }
};

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService';
import { ICONS } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { Culto, CheckIn } from '../types';

const Estatisticas: React.FC = () => {
  const [data, setData] = useState<{ cultos: Culto[], kidsCount: number, checkins: CheckIn[] } | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      const [cultos, kids, checkins] = await Promise.all([
        storageService.getCultos(),
        storageService.getCriancas(),
        storageService.getAllCheckins()
      ]);
      setData({ cultos, kidsCount: kids.length, checkins });
      setLoading(false);
    };
    load();
  }, []);

  if (loading || !data) {
    return <div className="text-center py-20 text-purple-main font-bold">Gerando relatórios...</div>;
  }

  const chartData = data.cultos.slice(0, 6).reverse().map(c => ({
    name: new Date(c.data).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
    total: data.checkins.filter(ch => ch.idCulto === c.id).length
  }));

  const avgAttendance = data.cultos.length > 0 ? (data.checkins.length / data.cultos.length).toFixed(1) : '0';

  return (
    <div className="space-y-10 animate-in fade-in duration-700">
       <header>
          <h1 className="text-4xl font-black text-purple-dark">Estatísticas</h1>
          <p className="text-gray-text font-medium">Insights sobre a frequência e crescimento do ministério.</p>
       </header>

       <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
          {[
            { label: 'Total Kids', val: data.kidsCount, color: 'text-purple-main', bg: 'bg-purple-main/5' },
            { label: 'Média/Culto', val: avgAttendance, color: 'text-yellow-600', bg: 'bg-yellow-main/10' },
            { label: 'Frequência Total', val: data.checkins.length, color: 'text-green-500', bg: 'bg-green-500/10' },
            { label: 'Sessões', val: data.cultos.length, color: 'text-blue-500', bg: 'bg-blue-500/10' }
          ].map((card, i) => (
            <div key={i} className={`${card.bg} p-10 rounded-[2.5rem] border border-transparent hover:border-white transition-all`}>
               <p className="text-[10px] font-black text-gray-text uppercase tracking-widest mb-2">{card.label}</p>
               <p className={`text-5xl font-black ${card.color}`}>{card.val}</p>
            </div>
          ))}
       </div>

       <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-gray-100">
          <div className="flex items-center gap-4 mb-10">
             <div className="bg-purple-main text-white p-3 rounded-2xl">{ICONS.BarChart}</div>
             <h3 className="text-2xl font-black text-purple-dark uppercase tracking-tight text-purple-dark">Presença nos Últimos 6 Cultos</h3>
          </div>

          <div className="h-[400px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 20, right: 30, left: 0, bottom: 20 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#999', fontSize: 12, fontWeight: 'bold'}} dy={15} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#999', fontSize: 12, fontWeight: 'bold'}} />
                <Tooltip cursor={{fill: '#f9f9f9'}} contentStyle={{borderRadius: '24px', border: 'none', boxShadow: '0 20px 40px rgba(0,0,0,0.1)', padding: '15px'}} />
                <Bar dataKey="total" radius={[12, 12, 0, 0]} barSize={50}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#7E3FA0' : '#FFC800'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
       </div>
    </div>
  );
};

export default Estatisticas;

