          <h1 className="text-3xl font-black text-purple-dark mb-2 uppercase tracking-tight">Cadastro Kids</h1>
          <p className="text-gray-text font-medium mb-10 text-sm">Preencha os dados do seu filho para o primeiro acesso.</p>

          <form onSubmit={handleSave} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 px-1">Nome</label>
                <input required type="text" value={form.nome} onChange={e => setForm({...form, nome: e.target.value})} className="w-full bg-gray-light p-4 rounded-2xl font-bold border-2 border-transparent focus:border-purple-main outline-none" placeholder="Ex: Lucas" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 px-1">Sobrenome</label>
                <input required type="text" value={form.sobrenome} onChange={e => setForm({...form, sobrenome: e.target.value})} className="w-full bg-gray-light p-4 rounded-2xl font-bold border-2 border-transparent focus:border-purple-main outline-none" placeholder="Ex: Silva" />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 px-1">Data de Nascimento</label>
                <input required type="date" value={form.dataNascimento} onChange={e => setForm({...form, dataNascimento: e.target.value})} className="w-full bg-gray-light p-4 rounded-2xl font-bold border-2 border-transparent focus:border-purple-main outline-none" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 px-1">Responsável</label>
                <input required type="text" value={form.responsavelNome} onChange={e => setForm({...form, responsavelNome: e.target.value})} className="w-full bg-gray-light p-4 rounded-2xl font-bold border-2 border-transparent focus:border-purple-main outline-none" placeholder="Nome do Pai/Mãe" />
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 px-1">WhatsApp (DDD + Número)</label>
              <input required type="tel" value={form.whatsapp} onChange={e => setForm({...form, whatsapp: e.target.value})} className="w-full bg-gray-light p-4 rounded-2xl font-bold border-2 border-transparent focus:border-purple-main outline-none" placeholder="67999999999" />
            </div>

            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 px-1">Observações Médicas</label>
              <textarea rows={2} value={form.observacoes} onChange={e => setForm({...form, observacoes: e.target.value})} className="w-full bg-gray-light p-4 rounded-2xl font-bold border-2 border-transparent focus:border-purple-main outline-none resize-none" placeholder="Alergias, restrições alimentares, etc..." />
            </div>

            <button 
              type="submit" 
              disabled={isSubmitting}
              className="w-full bg-purple-main text-white font-black py-6 rounded-[2rem] shadow-xl hover:bg-purple-dark transition-all disabled:opacity-50"
            >
              {isSubmitting ? 'SALVANDO...' : 'FINALIZAR CADASTRO'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default CriancaCadastro;

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { Crianca, CheckIn, Culto, PreCheckIn } from '../types';

const CultoAtivo: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const [culto, setCulto] = useState<Culto | null>(null);
  const [checkins, setCheckins] = useState<CheckIn[]>([]);
  const [allCriancas, setAllCriancas] = useState<Crianca[]>([]);
  const [preCheckins, setPreCheckins] = useState<PreCheckIn[]>([]);

  const [searchTerm, setSearchTerm] = useState('');
  const [codeQuery, setCodeQuery] = useState('');
  const [showCheckout, setShowCheckout] = useState<CheckIn | null>(null);
  const [checkoutName, setCheckoutName] = useState('');
  const [loading, setLoading] = useState(true);

  // Estados para Novo Cadastro e Etiqueta
  const [isAddingNew, setIsAddingNew] = useState(false);
  const [newKidForm, setNewKidForm] = useState({ nome: '', sobrenome: '', dataNascimento: '', responsavelNome: '', whatsapp: '', observacoes: '' });
  const [labelData, setLabelData] = useState<{ kid: Crianca, checkin: CheckIn } | null>(null);

  useEffect(() => {
    if (!id) return;

    const loadBasics = async () => {
      const kids = await storageService.getCriancas();
      setAllCriancas(kids);
    };
    loadBasics();

    const unsubCulto = storageService.subscribeToActiveCulto((c) => {
      if (!c || c.id !== id) {
        storageService.getCultos().then(list => {
          const found = list.find(item => item.id === id);
          if (found) setCulto(found);
          else navigate('/cultos');
        });
      } else {
        setCulto(c);
      }
    });

    const unsubCheckins = storageService.subscribeToCheckins(id, (list) => {
      setCheckins(list);
      setLoading(false);
    });

    const unsubPre = storageService.subscribeToPreCheckins(setPreCheckins);

    return () => {
      unsubCulto();
      unsubCheckins();
      unsubPre();
    };
  }, [id, navigate]);

  const activeCheckins = checkins.filter(c => c.status === 'presente');

  const triggerLabelPrint = (kid: Crianca, checkin: CheckIn) => {
    setLabelData({ kid, checkin });
    // Pequeno delay para garantir que o modal abriu antes de disparar o print do browser
    setTimeout(() => window.print(), 500);
  };

  const handleManualCheckin = async (kid: Crianca) => {
    if (activeCheckins.some(c => c.idCrianca === kid.id)) {
      alert(`${kid.nome} já está presente.`);
      return;
    }

    const newCheck: Omit<CheckIn, 'id'> = {
      idCrianca: kid.id,
      idCulto: id!,
      horaEntrada: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      status: 'presente'
    };

    try {
      await storageService.addCheckin(newCheck);
      // Pega o checkin que acabou de ser criado para a etiqueta
      const updatedCheckins = await storageService.getCheckins(id!);
      const lastCheck = updatedCheckins.find(c => c.idCrianca === kid.id && c.status === 'presente');
      if (lastCheck) triggerLabelPrint(kid, lastCheck);
      setSearchTerm('');
    } catch (e) {
      alert("Erro ao realizar check-in.");
    }
  };

  const handleQuickRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const newKid = await storageService.addCrianca({ ...newKidForm, createdAt: new Date().toISOString() });
      const kids = await storageService.getCriancas();
      setAllCriancas(kids);

      // Auto check-in
      await handleManualCheckin(newKid);
      setIsAddingNew(false);
      setNewKidForm({ nome: '', sobrenome: '', dataNascimento: '', responsavelNome: '', whatsapp: '', observacoes: '' });
    } catch (error) {
      alert("Erro ao cadastrar criança.");
    }
  };

  const handleCodeCheckin = async () => {
    const code = codeQuery.trim().toUpperCase();
    const pre = preCheckins.find(p => p.codigo === code && p.status === 'pendente');

    if (!pre) {
      alert('Código inválido ou já confirmado.');
      return;
    }

    const kid = allCriancas.find(k => k.id === pre.idCrianca);
    if (kid) {
      await handleManualCheckin(kid);
      await storageService.updatePreCheckin(pre.id, { 
        status: 'confirmado', 
        dataHoraCheckin: new Date().toISOString() 
      });
      setCodeQuery('');
    }
  };

  const handleConfirmCheckout = async () => {
    if (!showCheckout || !checkoutName) return;
    await storageService.updateCheckin(showCheckout.id, {
      status: 'saiu',
      horaSaida: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      quemRetirou: checkoutName
    });
    setShowCheckout(null);
    setCheckoutName('');
  };

  const handleEndCulto = async () => {
    if (activeCheckins.length > 0) {
      alert('Ainda há crianças presentes no Kids. Libere todas antes de encerrar.');
      return;
    }
    if (confirm('Deseja encerrar este culto definitivamente?')) {
      await storageService.updateCulto(id!, { 
        status: 'encerrado', 
        horaFim: new Date().toLocaleTimeString('pt-BR') 
      });
      navigate('/cultos');
    }
  };

  const filteredKids = searchTerm.length > 1 
    ? allCriancas.filter(k => (k.nome + ' ' + k.sobrenome).toLowerCase().includes(searchTerm.toLowerCase()))
    : [];

  if (loading) return <div className="text-center py-20 text-purple-main font-bold">Carregando culto ativo...</div>;

  return (
    <div className="space-y-8 pb-20 print:hidden">
      {/* Header Fixo */}
      <div className="bg-white p-8 rounded-[2.5rem] shadow-xl border-l-[12px] border-green-500 flex flex-col lg:flex-row lg:items-center justify-between gap-8 sticky top-0 z-30">
        <div className="flex-1">
          <div className="flex items-center gap-3 mb-2">
            <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${culto?.status === 'ativo' ? 'bg-green-100 text-green-600 animate-pulse' : 'bg-gray-100 text-gray-500'}`}>
              {culto?.status === 'ativo' ? '🟢 Em Andamento' : '⚪ Finalizado'}
            </span>
          </div>
          <h1 className="text-3xl font-black text-purple-dark uppercase tracking-tight">
            {culto?.tipo === 'Outros' ? culto.tipoManual : culto?.tipo}
          </h1>
        </div>

        <div className="flex items-center gap-4">
          <div className="bg-purple-main px-8 py-4 rounded-3xl text-white flex flex-col items-center justify-center shadow-lg">
            <span className="text-3xl font-black leading-none">{activeCheckins.length}</span>
            <span className="text-[10px] font-black uppercase tracking-tighter opacity-80 mt-1">Presentes</span>
          </div>
          {culto?.status === 'ativo' && (
            <button onClick={handleEndCulto} className="bg-red-500 hover:bg-red-600 text-white font-black px-8 py-4 rounded-3xl shadow-xl transition-all flex items-center gap-3">
              {ICONS.LogOut} <span>ENCERRAR</span>
            </button>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Coluna de Entrada */}
        <div className="lg:col-span-5 space-y-8">
          <div className="bg-yellow-main p-8 rounded-[3rem] shadow-lg">
            <h2 className="text-xl font-black text-purple-dark mb-6 uppercase flex items-center gap-3">
              {ICONS.QrCode} Check-in por Código
            </h2>
            <div className="flex gap-3">
              <input 
                type="text" 
                placeholder="Ex: KIDS-1234"
                value={codeQuery}
                onChange={(e) => setCodeQuery(e.target.value)}
                className="flex-1 p-5 rounded-2xl font-black text-2xl tracking-widest uppercase outline-none focus:ring-4 focus:ring-purple-main/20"
              />
              <button onClick={handleCodeCheckin} className="bg-purple-dark text-white px-8 rounded-2xl font-black hover:bg-purple-main transition-colors">OK</button>
            </div>
          </div>

          <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-gray-100">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-black text-purple-dark uppercase flex items-center gap-3">
                {ICONS.Search} Busca Manual
              </h2>
              <button 
                onClick={() => setIsAddingNew(true)}
                className="bg-purple-main/10 text-purple-main px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest hover:bg-purple-main hover:text-white transition-all"
              >
                + Novo Cadastro
              </button>
            </div>
            <input 
              type="text" 
              placeholder="Nome da criança..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-gray-light p-5 rounded-2xl font-bold mb-4 outline-none border-2 border-transparent focus:border-purple-main"
            />

            <div className="space-y-2 max-h-[300px] overflow-y-auto custom-scrollbar">
              {filteredKids.map(kid => (
                <button 
                  key={kid.id}
                  onClick={() => handleManualCheckin(kid)}
                  className="w-full flex items-center justify-between p-4 hover:bg-purple-main/5 rounded-2xl transition-colors group"
                >
                  <span className="font-bold text-gray-700">{kid.nome} {kid.sobrenome}</span>
                  <span className="text-purple-main opacity-0 group-hover:opacity-100 transition-opacity">{ICONS.Plus}</span>
                </button>
              ))}
              {searchTerm.length > 1 && filteredKids.length === 0 && (
                <div className="text-center py-6">
                  <p className="text-gray-400 text-sm font-bold mb-4">Criança não cadastrada.</p>
                  <button onClick={() => setIsAddingNew(true)} className="text-purple-main font-black underline">CADASTRAR AGORA</button>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Coluna de Presentes */}
        <div className="lg:col-span-7">
          <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-gray-100 min-h-[500px]">
            <h2 className="text-xl font-black text-purple-dark mb-8 uppercase flex items-center gap-3">
              {ICONS.Baby} Crianças na Sala
            </h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {activeCheckins.map(check => {
                const kid = allCriancas.find(k => k.id === check.idCrianca);
                return (
                  <div key={check.id} className="bg-gray-light p-6 rounded-[2.2rem] border-2 border-transparent hover:border-purple-main/20 transition-all">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <h4 className="font-black text-purple-dark text-lg truncate leading-tight">{kid?.nome}</h4>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Entrada: {check.horaEntrada}</p>
                      </div>
                      <button onClick={() => triggerLabelPrint(kid!, check)} className="text-purple-main p-2 hover:bg-white rounded-lg transition-colors">{ICONS.QrCode}</button>
                    </div>
                    <button onClick={() => setShowCheckout(check)} className="w-full bg-white text-purple-main border-2 border-purple-main hover:bg-purple-main hover:text-white py-3 rounded-xl font-black text-xs transition-all uppercase tracking-widest">REALIZAR SAÍDA</button>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      {/* Modal Novo Cadastro Rápido */}
      {isAddingNew && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-purple-dark/80 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300 overflow-y-auto max-h-[90vh]">
            <h2 className="text-2xl font-black text-purple-dark mb-6 uppercase">Novo Cadastro Rápido</h2>
            <form onSubmit={handleQuickRegister} className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <input required placeholder="Nome" value={newKidForm.nome} onChange={e => setNewKidForm({...newKidForm, nome: e.target.value})} className="bg-gray-light p-4 rounded-xl font-bold" />
                <input required placeholder="Sobrenome" value={newKidForm.sobrenome} onChange={e => setNewKidForm({...newKidForm, sobrenome: e.target.value})} className="bg-gray-light p-4 rounded-xl font-bold" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <input required type="date" value={newKidForm.dataNascimento} onChange={e => setNewKidForm({...newKidForm, dataNascimento: e.target.value})} className="bg-gray-light p-4 rounded-xl font-bold" />
                <input required placeholder="Responsável" value={newKidForm.responsavelNome} onChange={e => setNewKidForm({...newKidForm, responsavelNome: e.target.value})} className="bg-gray-light p-4 rounded-xl font-bold" />
              </div>
              <input required placeholder="WhatsApp" value={newKidForm.whatsapp} onChange={e => setNewKidForm({...newKidForm, whatsapp: e.target.value})} className="w-full bg-gray-light p-4 rounded-xl font-bold" />
              <textarea placeholder="Observações (Alergias, etc)" value={newKidForm.observacoes} onChange={e => setNewKidForm({...newKidForm, observacoes: e.target.value})} className="w-full bg-gray-light p-4 rounded-xl font-bold resize-none" rows={2} />
              <div className="grid grid-cols-2 gap-4 pt-4">
                <button type="button" onClick={() => setIsAddingNew(false)} className="bg-gray-100 text-gray-500 font-black py-4 rounded-2xl">CANCELAR</button>
                <button type="submit" className="bg-purple-main text-white font-black py-4 rounded-2xl shadow-xl">SALVAR E ENTRAR</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal Checkout */}
      {showCheckout && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-purple-dark/80 backdrop-blur-md">
          <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300 text-center">
            <h2 className="text-2xl font-black text-purple-dark mb-2 uppercase">Confirmar Saída</h2>
            <p className="text-gray-text font-bold mb-8">Quem veio buscar {allCriancas.find(k => k.id === showCheckout.idCrianca)?.nome}?</p>
            <input type="text" placeholder="Nome do responsável..." autoFocus value={checkoutName} onChange={(e) => setCheckoutName(e.target.value)} className="w-full bg-gray-light p-5 rounded-2xl font-bold mb-8 outline-none border-2 border-transparent focus:border-purple-main" />
            <div className="grid grid-cols-2 gap-4">
              <button onClick={() => setShowCheckout(null)} className="bg-gray-100 text-gray-500 font-black py-5 rounded-2xl">VOLTAR</button>
              <button onClick={handleConfirmCheckout} disabled={!checkoutName} className="bg-green-500 text-white font-black py-5 rounded-2xl shadow-xl disabled:opacity-50">CONFIRMAR</button>
            </div>
          </div>
        </div>
      )}

      {/* Modal Visualização de Etiqueta (Somente tela) */}
      {labelData && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/50 print:hidden">
          <div className="bg-white p-10 rounded-3xl shadow-2xl text-center max-w-xs">
            <p className="text-xs font-black text-purple-main mb-6 uppercase tracking-[0.2em]">Pré-visualização da Etiqueta</p>
            <div className="border-2 border-dashed border-gray-300 p-4 mb-8">
               <h3 className="text-2xl font-black text-black">{labelData.kid.nome}</h3>
               <p className="text-xs font-bold text-gray-600 mb-2">{labelData.kid.sobrenome}</p>
               <hr className="my-2" />
               <p className="text-[10px] font-black uppercase text-gray-400">Responsável</p>
               <p className="text-xs font-bold">{labelData.kid.responsavelNome}</p>
               <p className="text-[10px] font-black uppercase text-gray-400 mt-2">Culto / Entrada</p>
               <p className="text-xs font-bold">{culto?.tipo} | {labelData.checkin.horaEntrada}</p>
            </div>
            <button onClick={() => setLabelData(null)} className="w-full bg-purple-main text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest">FECHAR</button>
          </div>
        </div>
      )}

      {/* ÁREA DE IMPRESSÃO (Oculta na tela, visível apenas no print do browser) */}
      <div className="hidden print:block bg-white p-4" style={{ width: '50mm', height: '30mm', overflow: 'hidden' }}>
        {labelData && (
          <div className="text-black leading-none text-center">
            <h1 style={{ fontSize: '14pt', fontWeight: '900', margin: '0' }}>{labelData.kid.nome.toUpperCase()}</h1>
            <p style={{ fontSize: '8pt', margin: '1mm 0' }}>{labelData.kid.sobrenome}</p>
            <div style={{ borderTop: '1px solid black', margin: '1mm 0' }}></div>
            <p style={{ fontSize: '7pt', margin: '0' }}><b>Resp:</b> {labelData.kid.responsavelNome}</p>
            <p style={{ fontSize: '7pt', margin: '1mm 0' }}><b>Tel:</b> {labelData.kid.whatsapp}</p>
            {labelData.kid.observacoes && (
               <p style={{ fontSize: '6pt', background: '#000', color: '#fff', padding: '1px', marginTop: '1mm' }}>
                 <b>OBS:</b> {labelData.kid.observacoes}
               </p>
            )}
            <p style={{ fontSize: '5pt', marginTop: '2mm', opacity: '0.5' }}>IEADMS KIDS - {new Date().toLocaleDateString()}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default CultoAtivo;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { Culto } from '../types';

const PaisArea: React.FC = () => {
  const navigate = useNavigate();
  const [activeCulto, setActiveCulto] = useState<Culto | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let unsubscribe: (() => void) | undefined;
    try {
      unsubscribe = storageService.subscribeToActiveCulto((culto) => {
        setActiveCulto(culto);
        setLoading(false);
        setError(null);
      });
    } catch (e) {
      setLoading(false);
      setError("Erro de conexão com o servidor.");
    }
    return () => { if (unsubscribe) unsubscribe(); };
  }, []);

  return (
    <div className="min-h-screen bg-gray-light flex flex-col items-center p-6 pb-20 overflow-hidden">
      <div className="fixed top-[-100px] right-[-100px] w-80 h-80 bg-purple-main/5 rounded-full blur-3xl -z-10" />
      <div className="fixed bottom-[-50px] left-[-50px] w-60 h-60 bg-yellow-main/5 rounded-full blur-3xl -z-10" />

      <header className="w-full max-w-lg mt-10 text-center space-y-8 animate-in fade-in slide-in-from-top-4 duration-700">
        <div className="inline-block bg-white p-6 rounded-[2.5rem] shadow-2xl transform hover:rotate-6 transition-transform">
          <img src="https://api.dicebear.com/7.x/shapes/svg?seed=kids" alt="Fun" className="w-24 h-24" />
        </div>
        <div className="space-y-2">
          <h1 className="kids-font text-5xl font-black text-purple-dark leading-tight">Olá, Família!</h1>
          <p className="text-gray-text text-lg font-medium px-4 opacity-80">Pronto para o Culto Kids de hoje?</p>
        </div>
      </header>

      {loading ? (
        <div className="mt-20 flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-purple-main border-t-transparent rounded-full animate-spin"></div>
        </div>
      ) : (
        <div className="w-full max-w-lg mt-16 space-y-6 animate-in fade-in slide-in-from-bottom-6 duration-700">
          <button 
            onClick={() => navigate('/pais/pre-checkin')}
            disabled={!activeCulto}
            className={`w-full relative overflow-hidden p-8 rounded-[2.5rem] text-left transition-all transform active:scale-95 shadow-xl flex items-center justify-between border-b-8 ${
              activeCulto 
                ? 'bg-purple-main text-white border-purple-dark' 
                : 'bg-gray-200 text-gray-400 border-gray-300 cursor-not-allowed grayscale'
            }`}
          >
            <div className="relative z-10 flex-1">
