            <form onSubmit={handleQuickRegister} className="space-y-3">
              <div className="grid grid-cols-2 gap-3">
                <input required placeholder="Nome" value={newKidForm.nome} onChange={e => setNewKidForm({...newKidForm, nome: e.target.value})} className="bg-gray-light p-3 rounded-lg font-bold text-sm" />
                <input required placeholder="Sobrenome" value={newKidForm.sobrenome} onChange={e => setNewKidForm({...newKidForm, sobrenome: e.target.value})} className="bg-gray-light p-3 rounded-lg font-bold text-sm" />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <input required type="date" value={newKidForm.dataNascimento} onChange={e => setNewKidForm({...newKidForm, dataNascimento: e.target.value})} className="bg-gray-light p-3 rounded-lg font-bold text-sm" />
                <input required placeholder="Responsável" value={newKidForm.responsavelNome} onChange={e => setNewKidForm({...newKidForm, responsavelNome: e.target.value})} className="bg-gray-light p-3 rounded-lg font-bold text-sm" />
              </div>
              <input required placeholder="WhatsApp" value={newKidForm.whatsapp} onChange={e => setNewKidForm({...newKidForm, whatsapp: e.target.value})} className="w-full bg-gray-light p-3 rounded-lg font-bold text-sm" />
              <div className="grid grid-cols-2 gap-3 pt-2">
                <button type="button" onClick={() => setIsAddingNew(false)} className="bg-gray-100 text-gray-500 font-black py-3 rounded-xl text-xs uppercase">CANCELAR</button>
                <button type="submit" className="bg-purple-main text-white font-black py-3 rounded-xl shadow-lg text-xs uppercase">SALVAR E ENTRAR</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal Saída Compacto */}
      {showCheckout && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-purple-dark/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-2xl p-6 shadow-2xl text-center">
            <h2 className="text-lg font-black text-purple-dark mb-1 uppercase">Liberar Criança</h2>
            <p className="text-xs font-bold text-gray-500 mb-6">Quem veio buscar {allCriancas.find(k => k.id === showCheckout.idCrianca)?.nome}?</p>
            <input type="text" placeholder="Nome do responsável..." autoFocus value={checkoutName} onChange={(e) => setCheckoutName(e.target.value)} className="w-full bg-gray-light p-4 rounded-xl font-bold mb-6 outline-none text-sm" />
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowCheckout(null)} className="bg-gray-100 text-gray-500 font-black py-4 rounded-xl text-xs">VOLTAR</button>
              <button onClick={handleConfirmCheckout} disabled={!checkoutName} className="bg-green-500 text-white font-black py-4 rounded-xl shadow-lg disabled:opacity-50 text-xs uppercase">CONFIRMAR</button>
            </div>
          </div>
        </div>
      )}

      {/* Preview Etiqueta Otimizado */}
      {labelData && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/40 print:hidden">
          <div className="bg-white p-6 rounded-2xl shadow-2xl text-center max-w-xs w-full">
            <p className="text-[10px] font-black text-purple-main mb-4 uppercase">Etiqueta</p>
            <div className="border border-dashed border-gray-300 p-3 mb-6 bg-gray-50 rounded-lg">
               <h3 className="text-xl font-black text-black leading-tight">{labelData.kid.nome.toUpperCase()}</h3>
               <p className="text-xs font-bold text-gray-600 truncate">{labelData.kid.sobrenome}</p>
               <div className="my-2 border-t border-gray-200"></div>
               <p className="text-[8px] font-black uppercase text-gray-400">Responsável</p>
               <p className="text-[10px] font-bold">{labelData.kid.responsavelNome}</p>
            </div>
            <button onClick={() => setLabelData(null)} className="w-full bg-purple-main text-white py-3 rounded-xl font-black uppercase text-[10px]">FECHAR</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default CultoAtivo;

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService';
import { ICONS } from '../constants';
import { Crianca } from '../types';

const CriancasLista: React.FC = () => {
  const [kids, setKids] = useState<Crianca[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  const [form, setForm] = useState({
    nome: '', sobrenome: '', dataNascimento: '', responsavelNome: '', whatsapp: '', observacoes: ''
  });

  useEffect(() => {
    loadKids();
  }, []);

  const loadKids = async () => {
    setLoading(true);
    const list = await storageService.getCriancas();
    setKids(list);
    setLoading(false);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    const newKid: Omit<Crianca, 'id'> = {
      ...form,
      createdAt: new Date().toISOString()
    };
    await storageService.addCrianca(newKid);
    await loadKids();
    setIsAdding(false);
    setForm({ nome: '', sobrenome: '', dataNascimento: '', responsavelNome: '', whatsapp: '', observacoes: '' });
  };

  const filtered = kids.filter(k => 
    (k.nome + ' ' + k.sobrenome).toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
       <header className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div>
            <h1 className="text-2xl font-black text-purple-dark uppercase tracking-tight">Crianças</h1>
            <p className="text-xs text-gray-text font-medium">Gestão de cadastros e históricos.</p>
          </div>
          <button 
            onClick={() => setIsAdding(true)}
            className="bg-purple-main text-white font-black px-6 py-3 rounded-2xl shadow-lg flex items-center justify-center gap-2 hover:scale-105 transition-all text-xs uppercase"
          >
             {ICONS.Plus} Novo Cadastro
          </button>
       </header>

       <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
          <div className="relative w-full">
             <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">{ICONS.Search}</span>
             <input 
              type="text"
              placeholder="Pesquisar..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-11 pr-4 py-3 rounded-xl bg-gray-light border-2 border-transparent focus:border-purple-main outline-none font-bold text-sm"
             />
          </div>
       </div>

       {loading ? (
         <div className="text-center py-10 text-purple-main font-bold">Carregando...</div>
       ) : (
         <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {filtered.map(kid => (
              <div key={kid.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 p-5 flex items-start gap-4 hover:border-purple-main/20 transition-all">
                 <div className="bg-purple-main/10 text-purple-main w-12 h-12 rounded-xl flex items-center justify-center font-black text-xl shrink-0">
                    {kid.nome[0]}
                 </div>
                 <div className="flex-1 overflow-hidden">
                    <h3 className="font-black text-purple-dark text-sm truncate">{kid.nome} {kid.sobrenome}</h3>
                    <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-3">Resp: {kid.responsavelNome}</p>

                    <div className="flex items-center gap-2">
                       <a 
                        href={`https://wa.me/${kid.whatsapp}`} 
                        target="_blank" 
                        className="bg-green-500 text-white p-2 rounded-lg shadow-md"
                       >
                          {ICONS.Phone}
                       </a>
                       <div className="bg-gray-light px-3 py-1 rounded-lg">
                          <span className="text-[8px] font-black text-gray-400 uppercase block">Idade</span>
                          <span className="text-[10px] font-bold text-gray-700">{new Date().getFullYear() - new Date(kid.dataNascimento).getFullYear()} anos</span>
                       </div>
                    </div>
                 </div>
              </div>
            ))}
         </div>
       )}

       {isAdding && (
         <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-purple-dark/60 backdrop-blur-sm">
            <div className="bg-white w-full max-w-xl rounded-2xl p-6 shadow-2xl overflow-y-auto max-h-[90vh]">
               <h2 className="text-xl font-black text-purple-dark mb-6 uppercase tracking-tight">Novo Cadastro</h2>
               <form onSubmit={handleSave} className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <input required placeholder="Nome" value={form.nome} onChange={e => setForm({...form, nome: e.target.value})} className="bg-gray-light p-3 rounded-xl font-bold text-sm" />
                    <input required placeholder="Sobrenome" value={form.sobrenome} onChange={e => setForm({...form, sobrenome: e.target.value})} className="bg-gray-light p-3 rounded-xl font-bold text-sm" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <input required type="date" value={form.dataNascimento} onChange={e => setForm({...form, dataNascimento: e.target.value})} className="bg-gray-light p-3 rounded-xl font-bold text-sm" />
                    <input required placeholder="Responsável" value={form.responsavelNome} onChange={e => setForm({...form, responsavelNome: e.target.value})} className="bg-gray-light p-3 rounded-xl font-bold text-sm" />
                  </div>
                  <input required placeholder="WhatsApp" value={form.whatsapp} onChange={e => setForm({...form, whatsapp: e.target.value})} className="w-full bg-gray-light p-3 rounded-xl font-bold text-sm" />
                  <textarea rows={2} placeholder="Observações" value={form.observacoes} onChange={e => setForm({...form, observacoes: e.target.value})} className="w-full bg-gray-light p-3 rounded-xl font-bold text-sm resize-none" />
                  <div className="grid grid-cols-2 gap-4 pt-2">
                    <button type="button" onClick={() => setIsAdding(false)} className="bg-gray-100 text-gray-500 font-black py-4 rounded-xl text-xs uppercase">FECHAR</button>
                    <button type="submit" className="bg-purple-main text-white font-black py-4 rounded-xl shadow-lg text-xs uppercase">SALVAR</button>
                  </div>
               </form>
            </div>
         </div>
       )}
    </div>
  );
};

export default CriancasLista;

import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { Culto } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  isAdmin: boolean;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, isAdmin, onLogout }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [activeCulto, setActiveCulto] = useState<Culto | null>(null);

  useEffect(() => {
    if (isAdmin) {
      const unsubscribe = storageService.subscribeToActiveCulto((culto) => {
        setActiveCulto(culto);
      });
      return () => unsubscribe();
    }
  }, [isAdmin]);

  const menuItems = [
    { label: 'Painel', path: '/', icon: ICONS.Dashboard },
    { label: 'Crianças', path: '/criancas', icon: ICONS.Baby },
    { label: 'Histórico', path: '/cultos', icon: ICONS.Calendar },
    { label: 'Estatísticas', path: '/estatisticas', icon: ICONS.BarChart },
  ];

  if (!isAdmin || location.pathname.startsWith('/pais') || location.pathname === '/login') {
    return <div className="min-h-screen bg-gray-light font-sans">{children}</div>;
  }

  return (
    <div className="min-h-screen bg-gray-light flex flex-col md:flex-row">
      <aside className="hidden md:flex flex-col w-64 bg-purple-dark text-white sticky top-0 h-screen shadow-2xl z-40">
        <div className="p-6 border-b border-purple-main/20">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2 rounded-xl shadow-lg">
              <img src="https://api.dicebear.com/7.x/shapes/svg?seed=ieadms" alt="Logo" className="w-8 h-8" />
            </div>
            <div>
              <h1 className="kids-font text-xl font-bold leading-tight text-white">IEADMS</h1>
              <span className="text-yellow-main font-black tracking-widest text-[11px] uppercase">Culto Kids</span>
            </div>
          </div>
        </div>

        <nav className="flex-1 py-8 px-4 space-y-1.5">
          {menuItems.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center gap-4 px-5 py-3.5 rounded-2xl transition-all duration-300 font-bold text-sm ${
                  isActive 
                    ? 'bg-purple-main text-white shadow-lg translate-x-1' 
                    : 'text-white/70 hover:bg-white/10 hover:text-white'
                }`}
              >
                <span className={isActive ? 'text-yellow-main' : 'opacity-80'}>{item.icon}</span>
                {item.label}
              </Link>
            );
          })}
        </nav>

        {activeCulto && (
          <div className="m-5 p-5 bg-green-500/10 border border-green-500/30 rounded-[2rem]">
            <div className="flex items-center gap-2 text-green-400 mb-1.5">
              <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
              <span className="text-[10px] font-black uppercase tracking-widest">Culto Ativo</span>
            </div>
            <p className="text-sm font-black mb-3 text-white truncate">{activeCulto.tipo}</p>
            <button 
              onClick={() => navigate(`/cultos/ativo/${activeCulto.id}`)}
              className="w-full bg-green-600 hover:bg-green-500 text-white py-2 rounded-xl text-[11px] font-black transition-colors uppercase tracking-tight"
            >
              GERENCIAR
            </button>
          </div>
        )}

        <button 
          onClick={onLogout}
          className="m-8 flex items-center gap-3 text-white/50 hover:text-red-400 transition-colors font-bold px-4 text-xs"
        >
          {ICONS.LogOut}
          <span>Sair</span>
        </button>
      </aside>

      <header className="md:hidden bg-purple-dark text-white p-4 flex items-center justify-between sticky top-0 z-50 shadow-xl">
        <div className="flex items-center gap-2">
          <div className="bg-white p-1 rounded-lg">
            <img src="https://api.dicebear.com/7.x/shapes/svg?seed=ieadms" alt="Logo" className="w-6 h-6" />
          </div>
          <span className="kids-font font-bold text-md">IEADMS Kids</span>
        </div>
        <button onClick={onLogout} className="text-white/60 p-2">{ICONS.LogOut}</button>
      </header>

      <main className="flex-1 p-6 md:p-10 pb-24 md:pb-10 max-w-[1300px] mx-auto w-full">
        {children}
      </main>

      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 flex justify-around py-3 px-4 z-50 shadow-[0_-5px_15px_rgba(0,0,0,0.05)]">
        {menuItems.map((item) => {
          const isActive = location.pathname === item.path;
          return (
            <Link
              key={item.path}
              to={item.path}
              className={`flex flex-col items-center gap-1 transition-colors ${
                isActive ? 'text-purple-main' : 'text-gray-400'
              }`}
            >
              {item.icon}
              <span className="text-[10px] font-black uppercase tracking-tight">{item.label}</span>
            </Link>
          );
        })}
      </nav>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { Culto } from '../types';

const Dashboard: React.FC = () => {
  const navigate = useNavigate();
  const [activeCulto, setActiveCulto] = useState<Culto | null>(null);
  const [counts, setCounts] = useState({ kids: 0, sessions: 0, latest: [] as Culto[] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadData = async () => {
      const [kids, cultos] = await Promise.all([
        storageService.getCriancas(),
        storageService.getCultos()
      ]);

      setCounts({
        kids: kids.length,
        sessions: cultos.length,
        latest: cultos.slice(0, 4)
      });
      setLoading(false);
    };

    loadData();
    const unsubscribe = storageService.subscribeToActiveCulto(setActiveCulto);
    return () => unsubscribe();
  }, []);

  if (loading) {
    return <div className="flex items-center justify-center h-40 text-purple-main font-bold">Carregando painel...</div>;
  }

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-purple-dark tracking-tight uppercase">Painel Principal</h1>
          <p className="text-gray-text text-sm font-medium">Controle de fluxo em tempo real.</p>
        </div>

        {!activeCulto ? (
          <button
            onClick={() => navigate('/cultos/iniciar')}
            className="bg-yellow-main hover:bg-yellow-secondary text-purple-dark font-black px-8 py-4 rounded-[1.5rem] shadow-xl flex items-center justify-center gap-3 transition-all transform active:scale-95 group text-sm"
