      ...form,
      createdAt: new Date().toISOString()
    };
    await storageService.addCrianca(newKid);
    await loadKids();
    setIsAdding(false);
    setForm({ nome: '', sobrenome: '', dataNascimento: '', responsavelNome: '', whatsapp: '', observacoes: '' });
